// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 2000

int main() {
    int n, m;
    char grid[MAX][MAX];
    double beauty = 0.0;

    scanf("%d %d", &n, &m);
    for (int i = 0; i < n; i++) {
        scanf(" %s", grid[i]);
    }

    for (int size = 1; size <= n && size <= m; size++) {
        for (int i = 0; i <= n - size; i++) {
            for (int j = 0; j <= m - size; j++) {
                int unpainted = 0;
                char color = grid[i][j];
                for (int x = i; x < i + size; x++) {
                    for (int y = j; y < j + size; y++) {
                        if (grid[x][y] == '*') {
                            unpainted++;
                        } else if (grid[x][y] != color && color != '*') {
                            color = '-';
                        }
                    }
                }
                if (color != '-') {
                    beauty += (1.0 / 3.0) * (unpainted == 0) + (1.0 / (3 * (unpainted + 1))) * (unpainted > 0);
                }
            }
        }
    }

    printf("%.10f\n", beauty);
    return 0;
}

