const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const [n, m] = readline().split(' ').map(Number);
const grid = [];
for (let i = 0; i < n; i++) {
    grid.push(readline().trim());
}
let beauty = 0.0;

for (let size = 1; size <= n && size <= m; size++) {
    for (let i = 0; i <= n - size; i++) {
        for (let j = 0; j <= m - size; j++) {
            let unpainted = 0;
            let color = grid[i][j];
            for (let x = i; x < i + size; x++) {
                for (let y = j; y < j + size; y++) {
                    if (grid[x][y] === '*') {
                        unpainted++;
                    } else if (grid[x][y] !== color && color !== '*') {
                        color = '-';
                    }
                }
            }
            if (color !== '-') {
                beauty += (1.0 / 3.0) * (unpainted === 0) + (1.0 / (3 * (unpainted + 1))) * (unpainted > 0);
            }
        }
    }
}

